using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch circle on the xz plane.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr sketch = sketches->add(rootComp->xZConstructionPlane());
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCirles = sketchCurves->sketchCircles();
    if (!sketchCirles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr sketchCircle = sketchCirles->addByCenterRadius(centerPoint, 10);
    if (!sketchCircle)
        return false;

    // Get the profile from the sketch.
    Ptr sketchProfiles = sketch->profiles();
    if (!sketchProfiles)
        return false;
    Ptr profile = sketchProfiles->item(0);
    if (!profile)
        return false;

    // Create a cylinder with ExtrudeFeature using the profile above.
    Ptr features = rootComp->features();
    if (!features)
        return false;
    Ptr extrudeFeats = features->extrudeFeatures();
    if (!extrudeFeats)
        return false;
    Ptr distance = adsk::core::ValueInput::createByReal(2.0);
    if (!distance)
        return false;
    Ptr extrudeFeature =
        extrudeFeats->addSimple(profile, distance, adsk::fusion::FeatureOperations::NewBodyFeatureOperation);
    if (!extrudeFeature)
        return false;

    // Create a collection of source faces for replace
    Ptr brepFaces = extrudeFeature->endFaces();
    if (!brepFaces)
        return false;
    Ptr sourceFace = brepFaces->item(0);
    if (!sourceFace)
        return false;
    Ptr entities1 = adsk::core::ObjectCollection::create();
    if (!entities1)
        return false;
    entities1->add(sourceFace);

    // Create a construction plane as the target face
    Ptr offset = adsk::core::ValueInput::createByReal(5);
    if (!offset)
        return false;
    Ptr ctorPlanes = rootComp->constructionPlanes();
    if (!ctorPlanes)
        return false;
    Ptr ctorPlaneInput = ctorPlanes->createInput();
    if (!ctorPlaneInput)
        return false;
    ctorPlaneInput->setByOffset(sourceFace, offset);
    Ptr ctorPlane = ctorPlanes->add(ctorPlaneInput);
    if (!ctorPlane)
        return false;

    // Create a replace feature
    Ptr replaceFaceFeats = features->replaceFaceFeatures();
    if (!replaceFaceFeats)
        return false;
    bool isTangentChain = false;
    Ptr thickness = adsk::core::ValueInput::createByReal(0.5);
    if (!thickness)
        return false;
    Ptr replaceFaceFeatureInput =
        replaceFaceFeats->createInput(entities1, isTangentChain, ctorPlane);
    if (!replaceFaceFeatureInput)
        return false;
    Ptr replaceFaceFeature = replaceFaceFeats->add(replaceFaceFeatureInput);
    if (!replaceFaceFeature)
        return false;


    return true;
}
